// Tutorial controller — generated by add_tutorial.py
// No outlet connections required; manipulates patcher objects directly.
//
// Inlet 0: int (step index from umenu), bang (init), "prev" / "next"

inlets  = 1;
outlets = 0;

var STEPS         = [
  {
    "name": "Overview",
    "description": "This patch has 14 processing objects across 5 stages. Use the menu or prev/next to step through each stage."
  },
  {
    "name": "jit.world +3",
    "description": "jit.world \u2014 Provides a hidden OpenGL rendering context for Jitter. toggle \u2014 Sends 1 (on) or 0 (off) when clicked \u2014 starts/stops loops. jit.grab \u2014 Captures frames from a live camera or video source. jit.fpsgui \u2014 Shows the current processing frame rate."
  },
  {
    "name": "loadmess + flonum",
    "description": "loadmess \u2014 Sends a stored message when the patch loads (initializes defaults). flonum: scale image and pwindow."
  },
  {
    "name": "jit.matrixinfo +2",
    "description": "jit.matrixinfo: analyze the image. route: report the dim. vexpr \u2014 Evaluates a math expression on lists/vectors element-by-element."
  },
  {
    "name": "message +2",
    "description": "message: set size of pwindow & dim of matrix. message. jit.matrix \u2014 Stores and processes a matrix of data (adapt 0 = fixed size). jit.fpsgui \u2014 Shows the current processing frame rate."
  },
  {
    "name": "jit.pwindow",
    "description": "jit.pwindow \u2014 Displays a Jitter matrix as a video preview window."
  }
];
var ANNOTATION_IDS = ["tut-ann-0", "tut-ann-1", "tut-ann-2", "tut-ann-3", "tut-ann-4", "tut-ann-5"];
var PANEL_IDS      = ["tut-panel-0", "tut-panel-1", "tut-panel-2", "tut-panel-3", "tut-panel-4", "tut-panel-5"];
var STOW_RECT     = [10.0, 700.0, 70.0, 724.0];
var ACTIVE_RECTS  = [[689.0, 60.0, 909.0, 146.0], [448.0, 42.0, 668.0, 200.0], [816.0, 136.5, 1036.0, 240.5], [670.0, 134.5, 890.0, 238.5], [494.0, 252.0, 714.0, 392.0], [714.0, 476.5, 934.0, 544.5]];

var currentStep = -1;

// ---- inlet handlers ----

function bang() {
    gotoStep(0);
}

function msg_int(step) {
    gotoStep(step);
}

function prev() {
    gotoStep(Math.max(0, currentStep - 1));
}

function next() {
    gotoStep(Math.min(STEPS.length - 1, currentStep + 1));
}

// ---- core ----

function gotoStep(step) {
    if (step < 0 || step >= STEPS.length) return;

    var p = this.patcher;

    // Hide and stow ALL annotations and panels (so the previous step clears).
    for (var i = 0; i < ANNOTATION_IDS.length; i++) {
        var obj = p.getnamed(ANNOTATION_IDS[i]);
        if (obj) {
            obj.hidden = 1;
            obj.rect = STOW_RECT;
        }
    }
    for (var i = 0; i < PANEL_IDS.length; i++) {
        var obj = p.getnamed(PANEL_IDS[i]);
        if (obj) obj.hidden = 1;
    }

    currentStep = step;

    // Show this step's panel; show + reposition this step's annotation.
    var panel = p.getnamed(PANEL_IDS[step]);
    if (panel) panel.hidden = 0;

    var ann = p.getnamed(ANNOTATION_IDS[step]);
    if (ann) {
        ann.rect    = ACTIVE_RECTS[step];
        ann.hidden  = 0;
    }

    post("Tutorial step " + step + ": " + STEPS[step].name + "\n");
}
